import jwt

def decode_jwt(token):
    try:
        header = jwt.get_unverified_header(token)
        print('Header:')
        print(header)

        payload = jwt.decode(token, verify=False)
        print('\nPayload:')
        print(payload)
    except jwt.exceptions.InvalidTokenError as e:
        print("Invalid Token")

# Replace 'your_jwt_here' with the actual token to decode and verify
decode_jwt('your_jwt_here')